        function buildMvuOutputFormatEmphasizeContent() {
            return [
                '---',
                '变量输出格式强调:',
                '  rule: The following must be inserted to the end of reply, and cannot be omitted',
                '  format: |-',
                '    <UpdateVariable>',
                '    ...',
