        function selectedEjsVariablePath() {
            const option = mvuVariableOptions.value.find(item => item.id === selectedEjsVariableKey.value);
            return option?.path ?? mvuVariableOptions.value[0]?.path ?? `stat_data.${primaryMvuSystemName()}.好感度`;
        }
        function escapeRegExp(value) {
            return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        }
        function ejsCondition(rawCondition, variablePath) {
            const pathParts = variablePath.split('.').filter(Boolean);
            const pathTail = pathParts[pathParts.length - 1] ?? '好感度';
            const condition = rawCondition.trim();
            if (!condition)
                return 'qz_stage_value !== undefined';
            if (condition.includes('qz_stage_value'))
                return condition;
            if (/^[<>!=\s\d.&|()]+$/.test(condition))
                return condition.replace(new RegExp(escapeRegExp(pathTail), 'g'), 'qz_stage_value');
            const normalized = condition.replace(/\s+/g, '');
            const rangeMatch = normalized.match(/(-?\d+(?:\.\d+)?)(?:到|至|~|-)(-?\d+(?:\.\d+)?)/);
            if (rangeMatch) {
                return `qz_stage_value >= ${rangeMatch[1]} && qz_stage_value < ${rangeMatch[2]}`;
            }
            const numberMatch = normalized.match(/-?\d+(?:\.\d+)?/);
            if (numberMatch) {
                const value = numberMatch[0];
                if (/低于|小于|不到|以下/.test(normalized))
                    return `qz_stage_value < ${value}`;
                if (/高于|大于|超过/.test(normalized))
                    return `qz_stage_value > ${value}`;
                if (/至少|不低于|达到|以上|及以上/.test(normalized))
                    return `qz_stage_value >= ${value}`;
                if (/不超过|最多|以内|及以下/.test(normalized))
                    return `qz_stage_value <= ${value}`;
            }
            return condition.replace(new RegExp(escapeRegExp(pathTail), 'g'), 'qz_stage_value');
        }
