            }));
            const lines = [
                '<%_',
                `if (typeof qz_stage_value === 'undefined') var qz_stage_value = getvar(${JSON.stringify(variablePath)}, { defaults: 0 });`,
                '_%>',
            ];
            stages.forEach((stage, index) => {
                if (index === 0) {
                    lines.push(`<%_ if (${stage.condition}) { _%>`);
                }
                else if (index === stages.length - 1) {
                    lines.push('<%_ } else { _%>');
