default)';\n  }\n}\n</script>\n\n<template>\n  <div class=\"activity-panel\">\n    <div class=\"ap-header\">\n      <SvgIcons name=\"terminal\" :size=\"14\" />\n      <span class=\"ap-title\">AI 活动</span>\n      <span class=\"ap-count\">{{ activityStore.operations.length }}</span>\n      <button class=\"ap-clear\" @click=\"activityStore.clear\" title=\"清空\">\n        <SvgIcons name=\"trash\" :size=\"12\" />\n      </button>\n    </div>\n\n    <div class=\"ap-log\">\n      <div v-if=\"activityStore.operations.length === 0\" class=\"ap-empty\">\n        暂无操作记录\n      </div>\n\n      <div\n        v-for=\"op in activityStore.operations\"\n        :key=\"op.id\"\n        class=\"ap-entry\"\n        :class=\"{ 'is-write': isWriteOp(op) }\"\n      >\n        <span class=\"ap-time\">{{ formatTime(op.timestamp) }}</span>\n        <span class=\"ap-tool\" :style=\"{ color: getToolColor(op.tool) }\">{{ op.tool }}</span>\n        <span class=\"ap-summary\">{{ getOpSummary(op) }}</span>\n      </div>\n    </div>\n  </div>\n</template>\n\n<style scoped>\n.activity-panel {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  overflow: hidden;\n}\n\n.ap-header {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 6px 10px;\n  border-bottom: 1px solid var(--ide-border);\n  color: var(--ide-dim);\n  flex-shrink: 0;\n}\n\n.ap-title {\n  font-size: 13px;\n  font-weight: 600;\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n}\n\n.ap-count {\n  font-size: 10px;\n  padding: 1px 6px;\n  border-radius: 8px;\n  background: var(--ide-surface-2);\n  color: var(--ide-dim-2);\n  margin-left: auto;\n}\n\n.ap-clear {\n  background: transparent;\n  border: none;\n  color: var(--ide-dim-3);\n  cursor: pointer;\n  padding: 2px;\n  display: flex;\n  align-items: center;\n  border-radius: 3px;\n}\n\n.ap-clear:hover {\n  color: var(--ide-dim);\n  background: var(--ide-hover-strong);\n}\n\n.ap-log {\n  flex: 1;\n  overflow-y: auto;\n  overflow-x: hidden;\n  padding: 4px 0;\n  font-family: 'Cascadia Code', 'Fira Code', 'SF Mono', monospace;\n}\n\n.ap-log::-webkit-scrollbar { width: 3px; }\n\n.ap-log::-webkit-scrollbar-thumb {\n  background: var(--ide-scrollbar-soft);\n  border-radius: 2px;\n}\n\n.ap-empty {\n  text-align: center;\n  color: var(--ide-dim-3);\n  font-size: 11px;\n  padding: 20px;\n  font-family: inherit;\n}\n\n.ap-entry {\n  display: flex;\n  align-items: baseline;\n  gap: 6px;\n  padding: 2px 10px;\n  font-size: 12px;\n  line-height: 1.5;\n  color: var(--ide-dim);\n}\n\n.ap-entry:hover { background: var(--ide-surface); }\n\n.ap-entry.is-write {\n  border-left: 2px solid var(--ide-success-border);\n}\n\n.ap-time {\n  color: var(--ide-dim-3);\n  flex-shrink: 0;\n  font-variant-numeric: tabular-nums;\n}\n\n.ap-tool {\n  font-weight: 600;\n  flex-shrink: 0;\n  min-width: 50px;\n}\n\n.ap-summary {\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n</style>\n"],"sourceRoot":""}]);
